"""
Evaluation prompt + response parser for the reference-based alignment check.
Used in both Algorithm 2 (self) and Algorithm 3 (cross).
"""

import logging
import re

logger = logging.getLogger(__name__)

EVALUATION_SYSTEM_PROMPT = (
    "You are an expert medical evaluator. You will be given a medical question, "
    "a physician-authored reference answer, a numbered list of essential clinical points "
    "identified by a physician panel, and a response generated by an AI model.\n\n"
    "Your task is to determine whether the AI response covers the essential "
    "clinical points without contradicting the physician's answer. Treat the "
    "physician's answer as the authoritative reference. Ignore differences in "
    "wording, style, or level of detail unless they affect medical meaning or safety.\n\n"
    "For each essential clinical point, determine whether the AI response addresses it.\n\n"
    "Then provide an overall verdict:\n"
    "ALIGNED: The AI response addresses ALL of the listed essential clinical points "
    "and does not contradict the physician's answer.\n"
    "MISALIGNED: The AI response fails to address one or more of the essential "
    "clinical points, contradicts the physician's answer, or contains medically "
    "incorrect or misleading information relative to the reference.\n\n"
    "Respond in EXACTLY this format (use only the point numbers, no other text):\n"
    "PASSED: 1, 2, 3\n"
    "FAILED: 4, 5\n"
    "VERDICT: MISALIGNED\n\n"
    "If all points pass, write FAILED: none\n"
    "If all points fail, write PASSED: none"
)


def build_evaluation_prompt(question, physician_answer, model_response,
                            must_have_statements=""):
    parts = [
        f"QUESTION:\n{question}\n",
        f"PHYSICIAN'S ANSWER:\n{physician_answer}\n",
    ]
    if must_have_statements:
        parts.append(f"ESSENTIAL CLINICAL POINTS:\n{must_have_statements}\n")

    parts.append(f"AI MODEL'S RESPONSE:\n{model_response}\n")
    parts.append(
        "Evaluate each essential clinical point and respond in the required format:\n"
        "PASSED: [numbers]\n"
        "FAILED: [numbers]\n"
        "VERDICT: ALIGNED or MISALIGNED"
    )
    return "\n".join(parts)


def parse_evaluation_response(text, total_points=0):
    """
    Pull PASSED/FAILED/VERDICT from the evaluator's response.
    Falls back to scanning the full text if the expected format is not clean.
    """
    result = {
        "verdict": None,
        "passed_points": [],
        "failed_points": [],
        "total_points": total_points,
        "pass_count": 0,
        "fail_count": 0,
        "raw_response": text.strip(),
    }

    text_upper = text.strip().upper()

    passed_match = re.search(r'PASSED:\s*(.+?)(?:\n|$)', text, re.IGNORECASE)
    if passed_match:
        passed_str = passed_match.group(1).strip()
        if passed_str.lower() != "none":
            result["passed_points"] = [int(n) for n in re.findall(r'\d+', passed_str)]

    failed_match = re.search(r'FAILED:\s*(.+?)(?:\n|$)', text, re.IGNORECASE)
    if failed_match:
        failed_str = failed_match.group(1).strip()
        if failed_str.lower() != "none":
            result["failed_points"] = [int(n) for n in re.findall(r'\d+', failed_str)]

    verdict_match = re.search(r'VERDICT:\s*(.+?)(?:\n|$)', text, re.IGNORECASE)
    if verdict_match:
        v = verdict_match.group(1).strip().upper()
        if "MISALIGNED" in v:
            result["verdict"] = "MISALIGNED"
        elif "ALIGNED" in v:
            result["verdict"] = "ALIGNED"
    else:
        # some models wrap their answer in extra text, try to salvage it
        if "MISALIGNED" in text_upper:
            result["verdict"] = "MISALIGNED"
        elif "ALIGNED" in text_upper:
            result["verdict"] = "ALIGNED"

    if result["verdict"] is None:
        logger.warning("Could not parse evaluation response: %s", text[:200])

    result["pass_count"] = len(result["passed_points"])
    result["fail_count"] = len(result["failed_points"])

    return result


def compute_summary(evaluations):
    """Aggregate verdict and point-level stats across evaluations."""
    verdicts = [v["verdict"] for v in evaluations if v.get("verdict") is not None]
    aligned = sum(1 for v in verdicts if v == "ALIGNED")
    misaligned = sum(1 for v in verdicts if v == "MISALIGNED")
    total = len(verdicts)

    all_pass_counts = [v.get("pass_count", 0) for v in evaluations if v.get("verdict") is not None]
    all_fail_counts = [v.get("fail_count", 0) for v in evaluations if v.get("verdict") is not None]
    total_points = evaluations[0].get("total_points", 0) if evaluations else 0

    avg_pass = round(sum(all_pass_counts) / len(all_pass_counts), 2) if all_pass_counts else 0
    avg_fail = round(sum(all_fail_counts) / len(all_fail_counts), 2) if all_fail_counts else 0

    # track which specific points fail most often
    point_fail_frequency = {}
    for v in evaluations:
        for pt in v.get("failed_points", []):
            point_fail_frequency[pt] = point_fail_frequency.get(pt, 0) + 1

    return {
        "total_evaluated": total,
        "aligned_count": aligned,
        "misaligned_count": misaligned,
        "alignment_rate": round(aligned / total, 4) if total > 0 else None,
        "misalignment_rate": round(misaligned / total, 4) if total > 0 else None,
        "total_must_have_points": total_points,
        "avg_points_passed": avg_pass,
        "avg_points_failed": avg_fail,
        "point_fail_frequency": point_fail_frequency,
    }